const API_BASE_URL = 'https://api.example.com';
const LOCAL_DEVICE_BASE_URL = 'http://192.168.x.x';

const fetchFromApi = async (endpoint, options = {}) => {
  const url = `${API_BASE_URL}${endpoint}`;
  const headers = {
    'Content-Type': 'application/json',
    ...options.headers,
  };

  const response = await fetch(url, {
    ...options,
    headers,
  });

  if (!response.ok) {
    throw new Error(`API request failed with status ${response.status}`);
  }

  return response.json();
};

const fetchFromLocalDevice = async (endpoint, options = {}) => {
  const url = `${LOCAL_DEVICE_BASE_URL}${endpoint}`;
  const headers = {
    'Content-Type': 'application/json',
    ...options.headers,
  };

  const response = await fetch(url, {
    ...options,
    headers,
  });

  if (!response.ok) {
    throw new Error(`Local device request failed with status ${response.status}`);
  }

  return response.json();
};

